import{_ as t,o as n,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"9. Definitions","description":"","frontmatter":{"title":"9. Definitions","eba":"Mental Health Services 2024-2028","topics":["classifications"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/preliminary/9-definitions.md","filePath":"ebas/mental-health/common-terms/preliminary/9-definitions.md"}'),o={name:"ebas/mental-health/common-terms/preliminary/9-definitions.md"};function i(r,e,l,h,p,c){return n(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_9-definitions" tabindex="-1">9. Definitions <a class="header-anchor" href="#_9-definitions" aria-label="Permalink to &quot;9. Definitions&quot;">​</a></h1><p><strong>9.1</strong> In this Agreement, except where the context requires otherwise:</p><p><strong>(a)</strong> 2016 Agreement means the Victorian Public Services Mental Health Enterprise Agreement 2016-2020.</p><p><strong>(b)</strong> 2020 Agreement means the Victorian Public Services Mental Health Enterprise Agreement 2020-2024.</p><p><strong>(c)</strong> Act means Fair Work Act 2009 (Cth).</p><p><strong>(d)</strong> Adoption includes the placement of a Child (as defined in <a href="/eba/ebas/mental-health/common-terms/leave/50-parental-leave.html">clause 50</a> (Parental Leave)) by permanent care order and includes kinship care where it is comparable to adoption, having regard for all the circumstances.</p><p><strong>(e)</strong> Allied Health Professional means a person employed in any of the classifications as set out in <a href="/eba/ebas/mental-health/schedules/05-classification-definitions-applying-to-health-professionals.html">Schedule 5</a> of this Agreement excluding Lived and Living Experience Workers.</p><p><strong>(f)</strong> ANMF means the Australian Nursing and Midwifery Federation.</p><p><strong>(g)</strong> Bank Employee means a directly employed casual Employee who is engaged in relieving work of a casual nature.</p><p><strong>(h)</strong> BPEC means Best Practice Employment Commitment.</p><p><strong>(i)</strong> CATT shall mean Crisis Assessment Treatment Team and includes other work designated by the Employer as a community-based crisis response howsoever titled.</p><p><strong>(j)</strong> Commission means the Fair Work Commission or any successor body.</p><p><strong>(k)</strong> Consumer Consultant means a person employed by an Employer and classified as a Consumer Consultant in <a href="/eba/ebas/mental-health/schedules/05-classification-definitions-applying-to-health-professionals.html">Schedule 5</a>. Part 5, <a href="/eba/ebas/mental-health/common-terms/preliminary/4-division-into-sections-and-schedules.html">Clause 4.2</a>. For the avoidance of doubt, this does not include persons who volunteer as consumer consultants, in relation to that volunteer work.</p><p><strong>(l)</strong> Department means the Department of Health (Victoria) or any of its predecessors or successors.</p><p><strong>(m)</strong> EFT shall mean equivalent full time Employee.</p><p><strong>(n)</strong> Employee means a person employed by an Employer and engaged solely or predominantly in the provision of Mental Health Services, in a classification/occupation within the Agreement. In this Agreement, ‘engaged solely or predominately in the provision of Mental Health Services’, refers to the service, department, unit, or program of the Employer rather than the duties of the individual employee.</p><p><strong>(o)</strong> Employer means any of the employers listed in <a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Schedule 1</a> to this Agreement.</p><p><strong>(p)</strong> EO Act means the Equal Opportunity Act 2010 (Vic).</p><p><strong>(q)</strong> Family Carer Consultant means a person employed by an Employer and classified as a Family Carer Consultant in <a href="/eba/ebas/mental-health/schedules/05-classification-definitions-applying-to-health-professionals.html">Schedule 5</a>, Part 5, <a href="/eba/ebas/mental-health/common-terms/preliminary/4-division-into-sections-and-schedules.html">Clause 4.2</a>. For the avoidance of doubt, this does not include persons who volunteer as family carer consultants, in relation to that volunteer work.</p><p><strong>(r)</strong> FFPPOA means first full pay period on or after.</p><p><strong>(s)</strong> FW Regulations means the Fair Work Regulations 2009 (Cth) as amended or replaced from time to time.</p><p><strong>(t)</strong> HACSU means a Branch of the Health Services Union, known as the Health and Community Services Union.</p><p><strong>(u)</strong> HRP Act means the Health Practitioner Regulation National Law Act 2009 (Vic).</p><p><strong>(v)</strong> Immediate Family means:</p><p><strong>(i)</strong> a spouse including a former spouse a de facto partner and a former de facto partner of the Employee. A de facto partner means a person who, although not legally married to the Employee, lives with the Employee in a relationship as a couple on a genuine domestic basis (whether the Employee and the person are of the same sex or different sexes).</p><p><strong>(ii)</strong> a child or an adult child (including an adopted child, a stepchild, a current foster child of the Employee or an ex nuptial child), parent, grandparent, grandchild, or sibling of the Employee or the Employee’s spouse or the Employee&#39;s de facto partner.</p><p><strong>(iii)</strong> This definition includes step-relations as well as adoptive relations.</p><p><strong>(w)</strong> Lived and Living Experience Worker means an Employee employed in accordance with the definition listed at <a href="/eba/ebas/mental-health/schedules/05-classification-definitions-applying-to-health-professionals.html">Schedule 5</a>.</p><p><strong>(x)</strong> Management and Administrative Officer means a person employed in any of the classifications listed in <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement.</p><p><strong>(y)</strong> Mental Health and Wellbeing Act means the Mental Health and Wellbeing Act 2022 (Vic) or its successor.</p><p><strong>(z)</strong> Mental Health Industry Implementation Committee (MHIIC) means the committee referred to in <a href="/eba/ebas/mental-health/common-terms/preliminary/12-implementation-committees.html">clause 12.1</a> of this Agreement.</p><p><strong>(aa)</strong> Mental Health Officer (&#39;MHO&#39;) means a person employed by an Employer and classified in accordance with the MHO classification in <a href="/eba/ebas/mental-health/rpn-pen-mho/classification-staffing/110-mental-health-officers-classifications.html">clause 110</a>.</p><p><strong>(bb)</strong> Mental Health Services/Psychiatric Services means the delivery of human services concerned with the prevention of mental illness and the assessment, treatment, rehabilitation, maintenance and support of those persons who may be at risk of or suffering from mental illness or psychiatric disability by Employers listed in <a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Schedule 1</a>.</p><p><strong>(cc)</strong> NES means the National Employment Standards as contained in the Act.</p><p><strong>(dd)</strong> NMBA means the Nursing and Midwifery Board of Australia.</p><p><strong>(ee)</strong> OHS Act means the Occupational Health and Safety Act 2004 (Vic).</p><p><strong>(ff)</strong> Parties means, the Employers, HACSU and ANMF.</p><p><strong>(gg)</strong> Peer Worker means a person employed by an Employer and classified as a Peer Worker and classified as a Peer Worker in <a href="/eba/ebas/mental-health/schedules/05-classification-definitions-applying-to-health-professionals.html">Schedule 5</a> Part 5, Clauses 1.3, 2.3 or 3.3. For the avoidance of doubt, this does not include persons who volunteer as Peer Support Workers, in relation to that volunteer work.</p><p><strong>(hh)</strong> Pool Employee means a class of non-casual Employees who agree to be available for deployment across all or part of a Health Service.</p><p><strong>(ii)</strong> Psychiatric Enrolled Nurse (&#39;PEN&#39;) means a person employed by an Employer and classified in accordance with <a href="/eba/ebas/mental-health/rpn-pen-mho/classification-staffing/109-psychiatric-enrolled-nurse-classifications.html">clause 109</a> and registered as an Enrolled Nurse in Division 2 on the Register of Nurses of the NMBA established by the HRP Act and works within the scope of practice. This definition is intended for use as an industrial classification and for the purpose of this Agreement only, and does not imply specialist registration. The relevant qualification applicable is dealt with under the HRP Act.</p><p><strong>(jj)</strong> Registered Psychiatric Nurse (&#39;RPN&#39;) means a person employed by an Employer and classified in accordance with <a href="/eba/ebas/mental-health/rpn-pen-mho/classification-staffing/108-registered-psychiatric-nursing-classifications.html">clause 108</a>, and registered as a Registered Nurse in the Register of Nurses of the NMBA established by the HRP Act. This definition is intended for use as an industrial classification and for the purpose of this Agreement only,and does not imply specialist registration. The relevant qualification applicable is dealt with under the HRP Act.</p><p><strong>(kk)</strong> Relevant qualification/relevant component of a qualification etc. Where a provision of this Agreement requires consideration of the relevance of a qualification or certificate (including components of a qualification or certificate) or course of study or similar (education):</p><p><strong>(i)</strong> the main criteria for considering relevance are: <strong>(A)</strong> the nature of the education and <strong>(B)</strong> the current area of practice of the Employee; and</p><p><strong>(ii)</strong> other considerations may include: <strong>(A)</strong> the clinical or other area of work of the Employee <strong>(B)</strong> the classification and position description of the Employee; and /or <strong>(C)</strong> whether the education would assist the Employee in performing their role and/or assist in maintaining quality patient care and/or assist in the administration of the ward/unit/area in which the Employee is employed.</p><p><strong>(ll)</strong> Support Services Employee means a person employed in any of the classifications listed in <a href="/eba/ebas/mental-health/schedules/06-support-services-employee-classifications.html">Schedule 6</a> of this Agreement.</p><p><strong>(mm)</strong> Unions means the ANMF and HACSU.</p><p><strong>(nn)</strong> VHIA means Victorian Hospitals&#39; Industrial Association.</p><p><strong>(oo)</strong> Workplace Implementation Committee (WIC) means the committee referred to in <a href="/eba/ebas/mental-health/common-terms/preliminary/12-implementation-committees.html">clause 12.3</a> of this Agreement.</p><p><strong>(pp)</strong> WIRC Act means the Workplace Injury Rehabilitation and Compensation Act 2013 (Vic), or if applicable in the particular situation the Accident Compensation Act 1985 (Vic) or the Workers Compensation Act 1958 (Vic).</p>',49)])])}const f=t(o,[["render",i]]);export{d as __pageData,f as default};
